1	import { quote, claim, type Customer, type Item, type Incident } from "./claim-office.js";
2	
3	export interface CliResult {
4	  stdout: string;
5	  stderr: string;
6	  exitCode: number;
7	}
8	
9	interface QuoteStep {
10	  op?: "quote";
11	  items: Item[];
12	}
13	
14	interface ClaimStep {
15	  op: "claim";
16	  policy: number;
17	  incident: Incident;
18	}
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	interface Scenario {
23	  customer: Customer;
24	  steps: Step[];
25	}
26	
27	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
28	
29	function errorResult(message: string): CliResult {
30	  return { stdout: "", stderr: message, exitCode: 1 };
31	}
32	
33	export function runScenario(scenarioJson: string): CliResult {
34	  const scenario: Scenario = JSON.parse(scenarioJson);
35	  const results = [];
36	  for (const step of scenario.steps) {
37	    if (step.op === "claim") {
38	      const policyStep = scenario.steps[step.policy] as QuoteStep;
39	      const policyTypes = new Set(policyStep.items.map((item) => item.type));
40	      for (const damage of step.incident.damages) {
41	        if (!policyTypes.has(damage.itemType)) {
42	          return errorResult(`claim damage itemType ${damage.itemType} not in policy`);
43	        }
44	        if (damage.amount < 0) {
45	          return errorResult(`claim damage amount must be non-negative: ${damage.amount}`);
46	        }
47	      }
48	      results.push(claim({ items: policyStep.items }, step.incident));
49	      continue;
50	    }
51	    for (const item of step.items) {
52	      if (!KNOWN_ITEM_TYPES.has(item.type)) {
53	        return errorResult(`unknown item type: ${item.type}`);
54	      }
55	    }
56	    results.push({ premium: quote(scenario.customer, step.items) });
57	  }
58	  return { stdout: JSON.stringify({ results }), stderr: "", exitCode: 0 };
59	}
