const policyStep = scenario.steps[step.policy] as QuoteStep;
const policyTypes = new Set(policyStep.items.map((item) => item.type));
const damageCounts = new Map<string, number>();
for (const damage of step.incident.damages) {
  if (!policyTypes.has(damage.itemType)) {
    return errorResult(`claim damage itemType ${damage.itemType} not in policy`);
  }
  if (damage.amount < 0) {
    return errorResult(`claim damage amount must be non-negative: ${damage.amount}`);
  }
  damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
}
for (const [itemType, count] of damageCounts) {
  const policyCount = policyStep.items.filter((item) => item.type === itemType).length;
  if (count > policyCount) {
    return errorResult(`claim has more ${itemType} damages (${count}) than policy contains (${policyCount})`);
  }
}
